con:configuration.scriptText:
import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange, log)
ca.assertSchematronConstraints()

import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange)

context.allRecords = ca.getContentRecords()

con:config.script:
def authorTime = '/urn:referralOutcome/urn1:referralOutcomeHeader/urn1:accountableHealthcareProfessional/urn1:authorTime'
def signatureTime = '/urn:referralOutcome/urn1:referralOutcomeHeader/urn1:legalAuthenticator/urn1:signatureTime'

if (!context.allRecords) {
	testRunner.fail("No records")
	return
}
if (!context.dates) {
	def authorTimes = context.allRecords.collect { record -> record.firstElementAt(authorTime) }
	def signatureTimes = context.allRecords.collect { record -> record.firstElementAt(signatureTime) }

	context.dates = (authorTimes + signatureTimes).findAll().collect { it[0..7] }.unique()
	log.info "Unika datum: " + context.dates

	if (!context.dates) {
		testRunner.fail("No data")
	}
}

context.datePeriodStart = context.dates.pop()
context.datePeriodEnd = context.datePeriodStart

[context.datePeriodStart, context.datePeriodEnd]

con:configuration.scriptText:
import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange, log)
ca.assertSchematronConstraints()

import se.skl.rivta.tksupport.soapui.ContentAssertions def ca = new ContentAssertions(context, messageExchange)
def authorTime = '/urn:referralOutcome/urn1:referralOutcomeHeader/urn1:accountableHealthcareProfessional/urn1:authorTime' def signatureTime = '/urn:referralOutcome/urn1:referralOutcomeHeader/urn1:legalAuthenticator/urn1:signatureTime' def id = '/urn:referralOutcome/urn1:referralOutcomeHeader/urn1:documentId'
def condition = { record -> def before = [authorTime, signatureTime].every { xPath -> record.firstElementAt(xPath) == null || record.timestampIsBefore(xPath, context.datePeriodStart) } def after = [authorTime, signatureTime].every { xPath -> record.firstElementAt(xPath) == null || record.timestampIsAfter(xPath, context.datePeriodEnd) } return !before && !after }
def recordInfo = { record -> sprintf("DocumentId %s (authorTime:%s signatureTime:%s)", [id, authorTime, signatureTime].collect{record.firstElementAt(it)}) }
ca.assertFilteredResponse(context.allRecords, condition, recordInfo)

con:config.script:
if (context.dates.any()) {
	testRunner.gotoStepByName( "Calculate interval")
}
else if (testRunner.getResults().any{it.getStatus().toString() == 'FAILED'}) {
	testRunner.fail("One or more steps failed")
}

